1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	const BLOCK_OF_3_BASE_PREMIUM = 60;
4	
5	const BASE_PREMIUM: Record<string, number> = {
6	  sword: 100,
7	  amulet: 60,
8	  staff: 80,
9	  potion: 40,
10	  rune: 25,
11	  moonstone: 25,
12	};
13	
14	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
15	
16	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
17	type Step = { op: "quote"; items: Item[] };
18	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
19	type QuoteResult = { premium: number };
20	
21	const withFirstInsurance = (base: number): number =>
22	  base + base * FIRST_INSURANCE_SURCHARGE_RATE;
23	
24	const itemPremium = (item: Item): number => {
25	  const base = BASE_PREMIUM[item.type];
26	  const curseSurcharge = item.cursed ? base * 0.5 : 0;
27	  return base + curseSurcharge + base * FIRST_INSURANCE_SURCHARGE_RATE;
28	};
29	
30	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
31	
32	const componentGroupPremium = (type: string, count: number): number =>
33	  count === 3
34	    ? withFirstInsurance(BLOCK_OF_3_BASE_PREMIUM)
35	    : count * itemPremium({ type });
36	
37	const countByType = (items: Item[]): Map<string, number> => {
38	  const counts = new Map<string, number>();
39	  for (const item of items) {
40	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
41	  }
42	  return counts;
43	};
44	
45	const sumComponentPremiums = (components: Item[]): number =>
46	  Array.from(countByType(components)).reduce(
47	    (sum, [type, count]) => sum + componentGroupPremium(type, count),
48	    0,
49	  );
50	
51	const sumMainItemPremiums = (mainItems: Item[]): number =>
52	  mainItems.reduce((sum, item) => sum + itemPremium(item), 0);
53	
54	const sumItemPremiums = (items: Item[]): number => {
55	  const components = items.filter(isComponent);
56	  const mainItems = items.filter((item) => !isComponent(item));
57	  return sumMainItemPremiums(mainItems) + sumComponentPremiums(components);
58	};
59	
60	const quoteStep = (step: Step): QuoteResult => ({
61	  premium: Math.ceil(sumItemPremiums(step.items) + PROCESSING_FEE),
62	});
63	
64	export const runScenario = (scenario: Scenario): { results: QuoteResult[] } => ({
65	  results: scenario.steps.map(quoteStep),
66	});
